    public AuthenticatedSession createSession(SAMLResponse samlResponse) 
            throws SAMLProcessingException {
        if (samlResponse.getAssertions() == null || samlResponse.getAssertions().isEmpty()) {
            throw new SAMLProcessingException("No assertions found in SAML response");
        }
        
        SAMLAssertion assertion = samlResponse.getAssertions().get(0);
        
        validateAssertion(assertion);
        
        AuthenticatedSession session = new AuthenticatedSession();
        session.setSessionId(generateSessionId());
        session.setUserId(assertion.getSubject().getNameId());
        session.setIssuer(assertion.getIssuer());
        session.setCreatedAt(Instant.now());
        
        if (assertion.getConditions() != null && 
            assertion.getConditions().getNotOnOrAfter() != null) {
            session.setExpiresAt(Instant.parse(assertion.getConditions().getNotOnOrAfter()));
        } else {
            session.setExpiresAt(Instant.now().plusSeconds(3600));
        }
        
        session.setAttributes(assertion.getAttributes());
        
        if (assertion.getAuthnStatement() != null) {
            session.setSessionIndex(assertion.getAuthnStatement().getSessionIndex());
            session.setAuthnContext(assertion.getAuthnStatement().getAuthnContextClassRef());
        }
        
        sessionManager.storeSession(session);
        
        return session;
    }
    
    private void validateAssertion(SAMLAssertion assertion) throws SAMLProcessingException {
        if (assertion.getSubject() == null || assertion.getSubject().getNameId() == null) {
            throw new SAMLProcessingException("Assertion missing required Subject/NameID");
        }
        
        if (assertion.getConditions() != null) {
            String notBefore = assertion.getConditions().getNotBefore();
            String notOnOrAfter = assertion.getConditions().getNotOnOrAfter();
            
            Instant now = Instant.now();
            
            if (notBefore != null) {
                Instant notBeforeInstant = Instant.parse(notBefore);
                if (now.isBefore(notBeforeInstant)) {
                    throw new SAMLProcessingException("Assertion not yet valid");
                }
            }
            
            if (notOnOrAfter != null) {
                Instant notOnOrAfterInstant = Instant.parse(notOnOrAfter);
                if (now.isAfter(notOnOrAfterInstant)) {
                    throw new SAMLProcessingException("Assertion has expired");
                }
            }
        }
    }
    
    private String generateSessionId() {
        SecureRandom random = new SecureRandom();
        byte[] bytes = new byte[32];
        random.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
