class SessionManager {
    private Map<String, AuthenticatedSession> sessions;
    
    public SessionManager() {
        this.sessions = new HashMap<>();
    }
    
    public void storeSession(AuthenticatedSession session) {
        sessions.put(session.getSessionId(), session);
    }
    
    public AuthenticatedSession getSession(String sessionId) {
        AuthenticatedSession session = sessions.get(sessionId);
        if (session != null && !session.isValid()) {
            sessions.remove(sessionId);
            return null;
        }
        return session;
    }
    
    public void invalidateSession(String sessionId) {
        sessions.remove(sessionId);
    }
    
    public void cleanupExpiredSessions() {
        Iterator<Map.Entry<String, AuthenticatedSession>> iterator = 
            sessions.entrySet().iterator();
        while (iterator.hasNext()) {
            Map.Entry<String, AuthenticatedSession> entry = iterator.next();
            if (!entry.getValue().isValid()) {
                iterator.remove();
            }
        }
    }
}

class SAMLNamespaceContext implements NamespaceContext {
    public String getNamespaceURI(String prefix) {
        if ("saml".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:assertion";
        } else if ("samlp".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:protocol";
        }
        return null;
    }
    
    public String getPrefix(String namespaceURI) {
        return null;
    }
    
    public Iterator<String> getPrefixes(String namespaceURI) {
        return null;
    }
}

